      },
      {
        "name": "DualWriteOrderRepository",
        "responsibility": "Migration-phase repository that writes to both MongoDB and PostgreSQL, reads from a configurable primary. Implements the same OrderRepository interface. Handles write failures to the secondary store gracefully (log + alert, do not fail the request).",
