      },
      {
        "name": "BatchMigrator",
        "responsibility": "Offline batch process that backfills 8M historical order documents from MongoDB into PostgreSQL. Uses cursor-based pagination, transforms documents to relational schema, and writes in batches of 1000. Idempotent — safe to restart. Tracks progress via a migration_cursor table.",
        "boundaries": "Reads from MongoDB, writes to PostgreSQL. Runs as a separate process (not in the request path). Uses PostgreSQL advisory locks to prevent concurrent migration runs."
