 1→export type OrderState =
 2→  | "PENDING"
 3→  | "CONFIRMED"
 4→  | "SHIPPED"
 5→  | "DELIVERED"
 6→  | "CANCELLED";
 7→
 8→// AC1: Valid transitions map
 9→const VALID_TRANSITIONS: Record<OrderState, ReadonlySet<OrderState>> = {
10→  PENDING: new Set(["CONFIRMED", "CANCELLED"]),
11→  CONFIRMED: new Set(["SHIPPED", "CANCELLED"]),
12→  SHIPPED: new Set(["DELIVERED"]),
13→  DELIVERED: new Set(), // AC4: terminal state
14→  CANCELLED: new Set(), // AC3: terminal state
15→};
16→
17→export class InvalidTransitionError extends Error {
18→  readonly code = "INVALID_TRANSITION";
19→
20→  constructor(from: OrderState, to: OrderState) {
21→    super(`Cannot transition from ${from} to ${to}`);
22→    this.name = "InvalidTransitionError";
23→  }
24→}
25→
26→export class OrderStateMachine {
27→  /**
28→   * Attempt a state transition.
29→   * @returns the new state if the transition is valid
30→   * @throws InvalidTransitionError (with code "INVALID_TRANSITION") for invalid transitions
31→   */
32→  transition(currentState: OrderState, targetState: OrderState): OrderState {
33→    if (!VALID_TRANSITIONS[currentState].has(targetState)) {
34→      throw new InvalidTransitionError(currentState, targetState);
35→    }
36→    return targetState;
37→  }
38→}
