  3→export interface PaymentInput {
  4→  amount: number;
  5→  currency: string;
  6→  userId: string;
  7→  // additional fields as needed by domain
  8→  [key: string]: unknown;
  9→}
 10→
 11→export interface FraudCheckResult {
 12→  isFraudulent: boolean;
 13→}
