 15→export interface FraudService {
 16→  check(input: PaymentInput): Promise<FraudCheckResult>;
 17→}
 18→
 19→export interface ChargeResult {
 20→  success: boolean;
 21→  transactionId?: string;
 22→  declineReason?: string;
 23→}
 24→
 25→export interface PaymentGateway {
 26→  charge(input: PaymentInput): Promise<ChargeResult>;
 27→}
 28→
 29→export interface PaymentResult {
 30→  success: true;
 31→  transaction_id: string;
 32→}
 33→
 34→// ─── Error codes ──────────────────────────────────────────────────────────────
 35→
 36→export type PaymentErrorCode =
 37→  | "FRAUD_DETECTED"
 38→  | "PAYMENT_DECLINED"
 39→  | "FRAUD_SERVICE_UNAVAILABLE"
 40→  | "GATEWAY_UNAVAILABLE";
 41→
 42→export class PaymentError extends Error {
 43→  readonly code: PaymentErrorCode;
 44→  readonly cause?: unknown;
 45→
 46→  constructor(code: PaymentErrorCode, message: string, cause?: unknown) {
 47→    super(message);
 48→    this.name = "PaymentError";
 49→    this.code = code;
 50→    this.cause = cause;
 51→  }
 52→}
 53→
 54→// ─── Implementation ───────────────────────────────────────────────────────────
 55→
 56→export async function processPayment(
 57→  input: PaymentInput,
 58→  fraudService: FraudService,
 59→  gateway: PaymentGateway
 60→): Promise<PaymentResult> {
 61→  // Step 1: Fraud check
 62→  let fraudResult: FraudCheckResult;
 63→  try {
 64→    fraudResult = await fraudService.check(input);
 65→  } catch (err) {
 66→    throw new PaymentError(
 67→      "FRAUD_SERVICE_UNAVAILABLE",
 68→      "Fraud check service is unavailable",
 69→      err
 70→    );
 71→  }
 72→
 73→  // AC2 / AC6: Fraud flagged — do NOT call gateway
 74→  if (fraudResult.isFraudulent) {
 75→    throw new PaymentError("FRAUD_DETECTED", "Payment flagged as fraudulent");
 76→  }
 77→
 78→  // Step 2: Charge via payment gateway
 79→  let chargeResult: ChargeResult;
 80→  try {
 81→    chargeResult = await gateway.charge(input);
 82→  } catch (err) {
 83→    throw new PaymentError(
 84→      "GATEWAY_UNAVAILABLE",
 85→      "Payment gateway is unavailable",
 86→      err
 87→    );
 88→  }
 89→
 90→  // AC3: Gateway returned a decline
 91→  if (!chargeResult.success) {
 92→    throw new PaymentError(
 93→      "PAYMENT_DECLINED",
 94→      chargeResult.declineReason ?? "Payment was declined"
 95→    );
 96→  }
 97→
 98→  // AC1: All good
 99→  return {
100→    success: true,
101→    transaction_id: chargeResult.transactionId!,
102→  };
103→}
