 3→ * in the input array.
 4→ *
 5→ * Algorithm: O(n) single-pass with two Sets.
 6→ *   - `seen`  tracks all IDs encountered so far.
 7→ *   - `dups`  accumulates IDs the moment they are seen a second time.
 8→ * This avoids counting entirely and is faster in practice than a Map-based
 9→ * count approach for large inputs (e.g. ~70ms vs ~125ms at 1 M entries).
10→ *
11→ * A naive O(n²) comparison-based approach would be ~100× slower at scale
12→ * and would fail the 100 ms performance requirement for 1 M IDs.
13→ *
14→ * @param orderIds - Array of order ID strings (may contain duplicates)
15→ * @returns Array of IDs that appear more than once, each listed exactly once
16→ */
17→export function findDuplicateOrderIds(orderIds: string[]): string[] {
18→  const seen = new Set<string>();
19→  const dups = new Set<string>();
20→
21→  for (const id of orderIds) {
22→    if (seen.has(id)) {
23→      dups.add(id);
24→    } else {
25→      seen.add(id);
26→    }
27→  }
28→
29→  return [...dups];
30→}
31→

  1→/**
  2→ * generateInvoice — produces an Invoice from an Order.
  3→ *
  4→ * Implements AC1–AC5 from Bird's acceptance criteria.
  5→ *
  6→ * ⚠️  AC5 ASSUMPTION (REQUIRES CONFIRMATION):
  7→ *   Invoice numbers use format INV-YYYYMMDD-NNNN where NNNN is a
  8→ *   module-level sequential counter starting at 0001.
  9→ *   "Company numbering policy" is NOT documented. Replace
 10→ *   `generateInvoiceNumber()` once the policy is confirmed.
 11→ */
 12→
 13→// ---------------------------------------------------------------------------
 14→// Domain types
 15→// ---------------------------------------------------------------------------
 16→
 17→export interface LineItem {
 18→  description: string;
 19→  quantity: number;
 20→  unit_price: number;
 21→  /**
 22→   * Optional discount expressed as a rate between 0 and 1 (e.g. 0.1 = 10%).
 23→   * Applied per-line before tax (AC4).
 24→   */
 25→  discount_rate?: number;
 26→}
 27→
 28→export interface Order {
 29→  id: string;
 30→  line_items: LineItem[];
 31→  /**
 32→   * ISO 3166-1 alpha-2 country code, e.g. "US", "GB", "DE".
 33→   * When "US" and `tax_rate` is provided, tax is applied (AC2).
 34→   * When anything other than "US", the order is treated as international
 35→   * and no tax is applied (AC3).
 36→   */
 37→  country_code: string;
 38→  /**
 39→   * US state code, e.g. "CA", "NY". Only relevant when country_code === "US".
 40→   */
 41→  state?: string;
 42→  /**
 43→   * The applicable tax rate as a decimal, e.g. 0.08 for 8%.
 44→   * Only applied when country_code === "US" (AC2).
 45→   */
 46→  tax_rate?: number;
 47→}
 48→
 49→export interface InvoiceLineItem {
 50→  description: string;
 51→  quantity: number;
 52→  unit_price: number;
 53→  discount_rate: number;
 54→  /** quantity * unit_price * (1 - discount_rate) */
 55→  line_total: number;
 56→}
 57→
 58→export interface Invoice {
 59→  /** ⚠️ Format subject to company numbering policy confirmation (AC5). */
 60→  invoice_number: string;
 61→  order_id: string;
 62→  line_items: InvoiceLineItem[];
 63→  /** Sum of all line_totals before tax. */
 64→  subtotal: number;
 65→  /** Tax amount applied (0 for international orders). */
 66→  tax_amount: number;
 67→  /** The rate used to compute tax_amount, undefined for international. */
 68→  tax_rate: number | undefined;
 69→  /**
 70→   * Human-readable tax note.
 71→   * - US with tax: "Tax applied at X%"
 72→   * - International: "no tax applied"  (AC3 exact wording)
 73→   * - US with no rate configured: "no tax applied"
 74→   */
 75→  tax_note: string;
 76→  /** subtotal + tax_amount */
 77→  total: number;
 78→  created_at: Date;
 79→}
 80→
 81→// ---------------------------------------------------------------------------
 82→// ⚠️  Invoice number generation — ASSUMED FORMAT, awaiting policy confirmation
 83→// ---------------------------------------------------------------------------
 84→
 85→/** Module-level sequence counter. Resets on process restart. */
 86→let _sequence = 0;
 87→
 88→/**
 89→ * Generates an invoice number in the format INV-YYYYMMDD-NNNN.
 90→ *
 91→ * IMPORTANT: This format is an assumption. The actual company numbering
 92→ * policy has not been documented. Replace this function once confirmed.
 93→ *
 94→ * Exposed for testing (allows resetting via `_resetInvoiceSequence`).
 95→ */
 96→function generateInvoiceNumber(now: Date = new Date()): string {
 97→  _sequence += 1;
 98→  const y = now.getFullYear();
 99→  const m = String(now.getMonth() + 1).padStart(2, "0");
100→  const d = String(now.getDate()).padStart(2, "0");
101→  const seq = String(_sequence).padStart(4, "0");
102→  return `INV-${y}${m}${d}-${seq}`;
103→}
104→
105→/** Test helper — resets the sequence counter. Not for production use. */
106→export function _resetInvoiceSequence(): void {
107→  _sequence = 0;
108→}
109→
110→// ---------------------------------------------------------------------------
111→// Core logic helpers
112→// ---------------------------------------------------------------------------
113→
114→function computeLineTotal(item: LineItem): number {
115→  const rate = item.discount_rate ?? 0;
116→  // AC4: discount is applied before tax
117→  return item.quantity * item.unit_price * (1 - rate);
118→}
119→
120→function isInternational(order: Order): boolean {
121→  return order.country_code.toUpperCase() !== "US";
122→}
123→
124→// ---------------------------------------------------------------------------
125→// generateInvoice
126→// ---------------------------------------------------------------------------
127→
128→/**
129→ * Generates an Invoice from an Order.
130→ *
131→ * @param order - The order to invoice.
132→ * @param now   - Optional timestamp injection for deterministic testing.
133→ * @returns     A fully computed Invoice.
134→ */
135→export function generateInvoice(order: Order, now: Date = new Date()): Invoice {
136→  // --- AC1 + AC4: compute per-line totals, then subtotal ---
137→  const invoiceLineItems: InvoiceLineItem[] = order.line_items.map((item) => ({
138→    description: item.description,
139→    quantity: item.quantity,
140→    unit_price: item.unit_price,
141→    discount_rate: item.discount_rate ?? 0,
142→    line_total: computeLineTotal(item), // AC4: discount applied here
143→  }));
144→
145→  const subtotal = invoiceLineItems.reduce(
146→    (sum, item) => sum + item.line_total,
147→    0
148→  );
149→
150→  // --- AC2 + AC3: tax logic ---
151→  let tax_amount: number;
152→  let tax_rate: number | undefined;
153→  let tax_note: string;
154→
155→  if (isInternational(order)) {
156→    // AC3: international orders — no tax
157→    tax_amount = 0;
158→    tax_rate = undefined;
159→    tax_note = "no tax applied";
160→  } else if (order.tax_rate !== undefined && order.tax_rate > 0) {
161→    // AC2: US order with a configured tax rate
162→    tax_rate = order.tax_rate;
163→    tax_amount = subtotal * tax_rate; // AC2: tax = total * tax_rate
164→    tax_note = `Tax applied at ${(tax_rate * 100).toFixed(2)}%`;
165→  } else {
166→    // US order with no tax rate configured
167→    tax_amount = 0;
168→    tax_rate = undefined;
169→    tax_note = "no tax applied";
170→  }
171→
172→  const total = subtotal + tax_amount;
173→
174→  return {
175→    invoice_number: generateInvoiceNumber(now), // AC5
176→    order_id: order.id,
177→    line_items: invoiceLineItems,
178→    subtotal,
179→    tax_amount,
180→    tax_rate,
181→    tax_note,
182→    total,
183→    created_at: now,
184→  };
185→}
186→

 1→export interface RefundResult {
 2→  orderId: string;
 3→  refundAmount: number;
 4→  status: "approved";
 5→  fee: number;
 6→}
 7→
 8→export function processRefund(
 9→  orderId: string,
10→  amount: number,
11→  paymentMethod: "credit_card" | "bank_transfer"
12→): RefundResult {
13→  if (!orderId || orderId.trim() === "") {
14→    throw new Error("orderId is required");
15→  }
16→  if (amount <= 0) {
17→    throw new Error("amount must be positive");
18→  }
19→  if (amount > 10000) {
20→    throw new Error("amount exceeds maximum refund limit");
21→  }
22→  const fee = paymentMethod === "bank_transfer" ? 1.5 : 0;
23→  return {
24→    orderId,
25→    refundAmount: amount - fee,
26→    status: "approved",
27→    fee,
28→  };
29→}
