 1→import { CouponRepository } from "./coupon-repository";
 2→
 3→export class CouponError extends Error {
 4→  constructor(
 5→    message: string,
 6→    public readonly code: string
 7→  ) {
 8→    super(message);
 9→    this.name = "CouponError";
10→  }
11→}
12→
13→export class CouponService {
14→  constructor(private readonly repo: CouponRepository) {}
15→
16→  /**
17→   * Applies a coupon to the given cart total.
18→   * @returns The discounted total after applying the coupon.
19→   * @throws CouponError with an appropriate error code if the coupon cannot be applied.
20→   */
21→  applyCoupon(cartTotal: number, couponCode: string): number {
22→    const coupon = this.repo.getCoupon(couponCode);
23→
24→    if (coupon === null) {
25→      throw new CouponError(
26→        `Coupon code "${couponCode}" not found.`,
27→        "COUPON_NOT_FOUND"
28→      );
29→    }
30→
31→    if (coupon.expired) {
32→      throw new CouponError(
33→        `Coupon code "${couponCode}" has expired.`,
34→        "COUPON_EXPIRED"
35→      );
36→    }
37→
38→    if (coupon.minimumOrder !== undefined && cartTotal < coupon.minimumOrder) {
39→      throw new CouponError(
40→        `Order minimum of $${coupon.minimumOrder} not met. Cart total: $${cartTotal}.`,
41→        "ORDER_MINIMUM_NOT_MET"
42→      );
43→    }
44→
45→    if (coupon.singleUse && coupon.used) {
46→      throw new CouponError(
47→        `Coupon code "${couponCode}" has already been used.`,
48→        "COUPON_ALREADY_USED"
49→      );
50→    }
51→
52→    const discountMultiplier = 1 - coupon.discountPercent / 100;
53→    return cartTotal * discountMultiplier;
54→  }
55→}
