 1→export type CustomerStatus = "VIP" | "standard";
 2→
 3→export interface Customer {
 4→  status: CustomerStatus;
 5→}
 6→
 7→/**
 8→ * Calculates the discount amount for a given customer and order total.
 9→ *
10→ * Rules (in priority order):
11→ *  1. VIP customers with order total > 150 receive a 15% volume discount
12→ *     (volume rate overrides the standard VIP rate).
13→ *  2. VIP customers with order total ≤ 150 receive a 20% discount.
14→ *  3. Standard customers receive no discount regardless of order total.
15→ *
16→ * @param customer  - The customer object containing status information.
17→ * @param orderTotal - The total value of the order (must be >= 0).
18→ * @returns The discount amount (not the discounted price).
19→ */
20→export function calculateDiscount(customer: Customer, orderTotal: number): number {
21→  if (customer.status === "VIP" && orderTotal > 150) {
22→    // Volume discount: 15% — overrides VIP rate for large orders (AC4, AC5)
23→    return orderTotal * 0.15;
24→  }
25→
26→  if (customer.status === "VIP") {
27→    // Standard VIP discount: 20% (AC1, AC2)
28→    return orderTotal * 0.2;
29→  }
30→
31→  // Standard customers receive no discount (AC3)
32→  return 0;
33→}
34→

 1→export interface Customer {
 2→  /** Existing tier field — no longer used in discount calculation */
 3→  tier?: "premium" | "gold" | "standard";
 4→  /** Date the customer account was created */
 5→  accountCreatedAt: Date;
 6→  /** Full list of purchase dates for this customer */
 7→  purchases: Date[];
 8→}
 9→
10→const NEW_CUSTOMER_THRESHOLD_DAYS = 30;
11→const WIN_BACK_WINDOW_DAYS = 90;
12→
13→const NEW_CUSTOMER_DISCOUNT = 0.05;   // 5%
14→const WIN_BACK_DISCOUNT = 0.03;       // 3%
15→const ACTIVE_CUSTOMER_DISCOUNT = 0;   // 0%
16→
17→function daysBetween(earlier: Date, later: Date): number {
18→  const msPerDay = 1000 * 60 * 60 * 24;
19→  return (later.getTime() - earlier.getTime()) / msPerDay;
20→}
21→
22→/**
23→ * Calculate the discount rate for a customer based on account age
24→ * and recent purchase activity.
25→ *
26→ * @param customer - The customer to evaluate
27→ * @param now      - Reference date (defaults to current time; injectable for testing)
28→ * @returns Discount rate as a decimal (e.g. 0.05 = 5%)
29→ */
30→export function calculateDiscount(customer: Customer, now: Date = new Date()): number {
31→  const accountAgeDays = daysBetween(customer.accountCreatedAt, now);
32→
33→  // AC1: New customer — account less than 30 days old
34→  if (accountAgeDays < NEW_CUSTOMER_THRESHOLD_DAYS) {
35→    return NEW_CUSTOMER_DISCOUNT;
36→  }
37→
38→  // AC2 / AC3: Returning customer — check for purchases in the last 90 days
39→  const windowStart = new Date(now.getTime() - WIN_BACK_WINDOW_DAYS * 24 * 60 * 60 * 1000);
40→  const hasRecentPurchase = customer.purchases.some(
41→    (purchaseDate) => purchaseDate >= windowStart && purchaseDate <= now
42→  );
43→
44→  // AC3: Active returning customer — at least one purchase in the last 90 days
45→  if (hasRecentPurchase) {
46→    return ACTIVE_CUSTOMER_DISCOUNT;
47→  }
48→
49→  // AC2: Lapsed returning customer — no purchases in the last 90 days (win-back rate)
50→  return WIN_BACK_DISCOUNT;
51→}
52→

 1→/**
 2→ * Shipping Calculator
 3→ *
 4→ * Supported destinations and their per-kg rates:
 5→ *   - "domestic"         → weight * 2.5  (standard ground)
 6→ *   - "international"    → weight * 7.5  (cross-border)
 7→ *   - "express_domestic" → weight * 4.0  (expedited domestic)
 8→ *   - "freight"          → weight * 1.5  (bulk / cheaper per-kg)
 9→ *
10→ * Validation:
11→ *   - Weight must be > 0; otherwise throws with code INVALID_WEIGHT.
12→ *   - Unknown destination strings throw with code UNKNOWN_DESTINATION.
13→ *
14→ * Signature is intentionally unchanged per MJ's constraint.
15→ */
16→
17→export class ShippingError extends Error {
18→  constructor(
19→    message: string,
20→    public readonly code: "INVALID_WEIGHT" | "UNKNOWN_DESTINATION"
21→  ) {
22→    super(message);
23→    this.name = "ShippingError";
24→  }
25→}
26→
27→const RATES: Record<string, number> = {
28→  domestic: 2.5,
29→  international: 7.5,
30→  express_domestic: 4.0,
31→  freight: 1.5,
32→};
33→
34→export function calculateShipping(weight: number, destination: string): number {
35→  if (weight <= 0) {
36→    throw new ShippingError(
37→      `Invalid weight: ${weight}. Weight must be greater than 0.`,
38→      "INVALID_WEIGHT"
39→    );
40→  }
41→
42→  const rate = RATES[destination];
43→
44→  if (rate === undefined) {
45→    throw new ShippingError(
46→      `Unknown destination: "${destination}". Valid destinations are: ${Object.keys(RATES).join(", ")}.`,
47→      "UNKNOWN_DESTINATION"
48→    );
49→  }
50→
51→  return weight * rate;
52→}
53→

 1→/**
 2→ * Tax brackets:
 3→ *   income <= 0          : throws INVALID_INCOME
 4→ *   0 < income < 10_000  : 0%  (tax = 0)
 5→ *   10_000 <= income <= 50_000  : 10% flat
 6→ *   50_001 <= income <= 150_000 : 25% flat
 7→ *   income > 150_000            : 40% flat
 8→ */
 9→
10→export class TaxError extends Error {
11→  constructor(
12→    public readonly code: string,
13→    message: string
14→  ) {
15→    super(message);
16→    this.name = "TaxError";
17→  }
18→}
19→
20→export function calculateTax(income: number): number {
21→  if (income <= 0) {
22→    throw new TaxError(
23→      "INVALID_INCOME",
24→      `Income must be a positive number, received: ${income}`
25→    );
26→  }
27→
28→  if (income < 10_000) {
29→    return 0;
30→  }
31→
32→  if (income <= 50_000) {
33→    return income * 0.10;
34→  }
35→
36→  if (income <= 150_000) {
37→    return income * 0.25;
38→  }
39→
40→  return income * 0.40;
41→}
