 1→/**
 2→ * Weight bracket classifier for parcels.
 3→ *
 4→ * Brackets:
 5→ *   standard : 0 < weight < 10 kg
 6→ *   heavy    : 10 <= weight < 50 kg
 7→ *   freight  : 50 <= weight <= 1000 kg
 8→ *
 9→ * Throws a validation error for weight <= 0 or weight > 1000.
10→ */
11→
12→export class WeightValidationError extends Error {
13→  constructor(message: string) {
14→    super(message);
15→    this.name = "WeightValidationError";
16→  }
17→}
18→
19→export function classifyWeight(weight: number): "standard" | "heavy" | "freight" {
20→  if (weight <= 0) {
21→    throw new WeightValidationError(
22→      `Invalid weight: ${weight} kg. Weight must be greater than 0.`
23→    );
24→  }
25→
26→  if (weight > 1000) {
27→    throw new WeightValidationError(
28→      `Invalid weight: ${weight} kg. Weight must not exceed 1000 kg.`
29→    );
30→  }
31→
32→  if (weight < 10) {
33→    return "standard";
34→  }
35→
36→  if (weight < 50) {
37→    return "heavy";
38→  }
39→
40→  return "freight";
41→}
