  1→/**
  2→ * PATCH /users/:id/email
  3→ *
  4→ * Updates a user's email address.
  5→ *
  6→ * Injected dependency: userRepository
  7→ *   - findById(id)           → User | null
  8→ *   - findByEmail(email)     → User | null
  9→ *   - updateEmail(id, email) → User  (returns updated user)
 10→ */
 11→
 12→// ─── Minimal Express-compatible interfaces ────────────────────────────────────
 13→// Defined locally so this module has no runtime dependency on the express package.
 14→
 15→export interface AppRequest {
 16→  params: Record<string, string>;
 17→  body: Record<string, unknown>;
 18→}
 19→
 20→export interface AppResponse {
 21→  status(code: number): AppResponse;
 22→  json(body: unknown): AppResponse;
 23→}
 24→
 25→// ─── Domain types ─────────────────────────────────────────────────────────────
 26→
 27→export interface User {
 28→  id: string;
 29→  email: string;
 30→  [key: string]: unknown;
 31→}
 32→
 33→export interface UserRepository {
 34→  findById(id: string): Promise<User | null>;
 35→  findByEmail(email: string): Promise<User | null>;
 36→  updateEmail(id: string, email: string): Promise<User>;
 37→}
 38→
 39→// ─── Constants ────────────────────────────────────────────────────────────────
 40→
 41→const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 42→
 43→// ─── Handler factory ──────────────────────────────────────────────────────────
 44→
 45→/**
 46→ * Factory — binds the repository and returns the Express route handler.
 47→ *
 48→ * Usage:
 49→ *   router.patch('/users/:id/email', makePatchUserEmail(userRepository));
 50→ */
 51→export function makePatchUserEmail(
 52→  userRepository: UserRepository,
 53→): (req: AppRequest, res: AppResponse) => Promise<void> {
 54→  return async function patchUserEmail(req: AppRequest, res: AppResponse): Promise<void> {
 55→    const { id } = req.params;
 56→    const { email } = req.body;
 57→
 58→    // AC3 — validate email format before any DB work
 59→    if (typeof email !== 'string' || !EMAIL_REGEX.test(email)) {
 60→      res.status(400).json({
 61→        error: {
 62→          code: 'INVALID_EMAIL_FORMAT',
 63→          message: 'The provided email address is not valid.',
 64→        },
 65→      });
 66→      return;
 67→    }
 68→
 69→    // AC4 — user must exist
 70→    const user = await userRepository.findById(id);
 71→    if (!user) {
 72→      res.status(404).json({
 73→        error: {
 74→          code: 'USER_NOT_FOUND',
 75→          message: `No user found with id '${id}'.`,
 76→        },
 77→      });
 78→      return;
 79→    }
 80→
 81→    // AC5 — same email → idempotent 200, no write
 82→    if (user.email === email) {
 83→      res.status(200).json({ user });
 84→      return;
 85→    }
 86→
 87→    // AC2 — email must not be taken by a different user
 88→    const existing = await userRepository.findByEmail(email);
 89→    if (existing) {
 90→      res.status(409).json({
 91→        error: {
 92→          code: 'EMAIL_ALREADY_IN_USE',
 93→          message: 'That email address is already associated with another account.',
 94→        },
 95→      });
 96→      return;
 97→    }
 98→
 99→    // AC1 — happy path: update and return new state
100→    const updatedUser = await userRepository.updateEmail(id, email);
101→    res.status(200).json({ user: updatedUser });
102→  };
103→}
