/**
 * generateInvoice — produces an Invoice from an Order.
 *
 * Implements AC1–AC5 from Bird's acceptance criteria.
 *
 * ⚠️  AC5 ASSUMPTION (REQUIRES CONFIRMATION):
 *   Invoice numbers use format INV-YYYYMMDD-NNNN where NNNN is a
 *   module-level sequential counter starting at 0001.
 *   "Company numbering policy" is NOT documented. Replace
 *   `generateInvoiceNumber()` once the policy is confirmed.
 */

// ---------------------------------------------------------------------------
// Domain types
// ---------------------------------------------------------------------------

export interface LineItem {
  description: string;
  quantity: number;
  unit_price: number;
  /**
   * Optional discount expressed as a rate between 0 and 1 (e.g. 0.1 = 10%).
   * Applied per-line before tax (AC4).
   */
  discount_rate?: number;
}

export interface Order {
  id: string;
  line_items: LineItem[];
  /**
   * ISO 3166-1 alpha-2 country code, e.g. "US", "GB", "DE".
   * When "US" and `tax_rate` is provided, tax is applied (AC2).
   * When anything other than "US", the order is treated as international
   * and no tax is applied (AC3).
   */
  country_code: string;
  /**
   * US state code, e.g. "CA", "NY". Only relevant when country_code === "US".
   */
  state?: string;
  /**
   * The applicable tax rate as a decimal, e.g. 0.08 for 8%.
   * Only applied when country_code === "US" (AC2).
   */
  tax_rate?: number;
}

export interface InvoiceLineItem {
  description: string;
  quantity: number;
  unit_price: number;
  discount_rate: number;
  /** quantity * unit_price * (1 - discount_rate) */
  line_total: number;
}

export interface Invoice {
  /** ⚠️ Format subject to company numbering policy confirmation (AC5). */
  invoice_number: string;
  order_id: string;
  line_items: InvoiceLineItem[];
  /** Sum of all line_totals before tax. */
  subtotal: number;
  /** Tax amount applied (0 for international orders). */
  tax_amount: number;
  /** The rate used to compute tax_amount, undefined for international. */
  tax_rate: number | undefined;
  /**
   * Human-readable tax note.
   * - US with tax: "Tax applied at X%"
   * - International: "no tax applied"  (AC3 exact wording)
   * - US with no rate configured: "no tax applied"
   */
  tax_note: string;
  /** subtotal + tax_amount */
  total: number;
  created_at: Date;
}

// ---------------------------------------------------------------------------
// ⚠️  Invoice number generation — ASSUMED FORMAT, awaiting policy confirmation
// ---------------------------------------------------------------------------

/** Module-level sequence counter. Resets on process restart. */
let _sequence = 0;

/**
 * Generates an invoice number in the format INV-YYYYMMDD-NNNN.
 *
 * IMPORTANT: This format is an assumption. The actual company numbering
 * policy has not been documented. Replace this function once confirmed.
 *
 * Exposed for testing (allows resetting via `_resetInvoiceSequence`).
 */
function generateInvoiceNumber(now: Date = new Date()): string {
  _sequence += 1;
  const y = now.getFullYear();
  const m = String(now.getMonth() + 1).padStart(2, "0");
  const d = String(now.getDate()).padStart(2, "0");
  const seq = String(_sequence).padStart(4, "0");
  return `INV-${y}${m}${d}-${seq}`;
}

/** Test helper — resets the sequence counter. Not for production use. */
export function _resetInvoiceSequence(): void {
  _sequence = 0;
}

// ---------------------------------------------------------------------------
// Core logic helpers
// ---------------------------------------------------------------------------

function computeLineTotal(item: LineItem): number {
  const rate = item.discount_rate ?? 0;
  // AC4: discount is applied before tax
  return item.quantity * item.unit_price * (1 - rate);
}

function isInternational(order: Order): boolean {
  return order.country_code.toUpperCase() !== "US";
}

// ---------------------------------------------------------------------------
// generateInvoice
// ---------------------------------------------------------------------------

/**
 * Generates an Invoice from an Order.
 *
 * @param order - The order to invoice.
 * @param now   - Optional timestamp injection for deterministic testing.
 * @returns     A fully computed Invoice.
 */
export function generateInvoice(order: Order, now: Date = new Date()): Invoice {
  // --- AC1 + AC4: compute per-line totals, then subtotal ---
  const invoiceLineItems: InvoiceLineItem[] = order.line_items.map((item) => ({
    description: item.description,
    quantity: item.quantity,
    unit_price: item.unit_price,
    discount_rate: item.discount_rate ?? 0,
    line_total: computeLineTotal(item), // AC4: discount applied here
  }));

  const subtotal = invoiceLineItems.reduce(
    (sum, item) => sum + item.line_total,
    0
  );

  // --- AC2 + AC3: tax logic ---
  let tax_amount: number;
  let tax_rate: number | undefined;
  let tax_note: string;

  if (isInternational(order)) {
    // AC3: international orders — no tax
    tax_amount = 0;
    tax_rate = undefined;
    tax_note = "no tax applied";
  } else if (order.tax_rate !== undefined && order.tax_rate > 0) {
    // AC2: US order with a configured tax rate
    tax_rate = order.tax_rate;
    tax_amount = subtotal * tax_rate; // AC2: tax = total * tax_rate
    tax_note = `Tax applied at ${(tax_rate * 100).toFixed(2)}%`;
  } else {
    // US order with no tax rate configured
    tax_amount = 0;
    tax_rate = undefined;
    tax_note = "no tax applied";
  }

  const total = subtotal + tax_amount;

  return {
    invoice_number: generateInvoiceNumber(now), // AC5
    order_id: order.id,
    line_items: invoiceLineItems,
    subtotal,
    tax_amount,
    tax_rate,
    tax_note,
    total,
    created_at: now,
  };
}

