      },
      {
        "from": "BatchMigrator",
        "to": "MongoOrderRepository",
        "contract": "findOrdersByCursor(cursor, batchSize): Promise<{orders, nextCursor}>. Read-only cursor-based pagination.",
        "coupling_type": "data — read-only batch access"
      },
      {
        "from": "BatchMigrator",
